import React, { useState } from 'react';
import { DefaultTemplate } from '../DefaultTemplate';
import { PostList } from '../../components/PostList';
import { Introduce } from '../../components/common/Introduce';
import { PAGE_PER_COUNT } from '../../config/constants';

type Props = {
  indexQuery: Queries.IndexPageQuery;
}

export const Home: React.FC<Props> = ({ indexQuery }) => {
  const totalPageNumber = Math.floor(indexQuery.allMarkdownRemark.totalCount / PAGE_PER_COUNT)
  const [selectedPageNumber, setSelectedPageNumber] = useState(0);
  const mdList = indexQuery.allMarkdownRemark?.nodes as Queries.MarkdownRemark[];

  return (
    <DefaultTemplate>
      <Introduce />
      <PostList
        mdList={mdList}
        totalCount={indexQuery.allMarkdownRemark?.totalCount | 0}
      />

      {/*<Pagination*/}
      {/*  selectedPageNumber={selectedPageNumber}*/}
      {/*  totalPageNumber={totalPageNumber}*/}
      {/*/>*/}
    </DefaultTemplate>
  );
};
